import { useState, useEffect } from "react";
import axios from "axios";

const API = "http://127.0.0.1:5000";

export default function App() {
  const [email, setEmail] = useState("");
  const [apiKey, setApiKey] = useState("");
  const [usage, setUsage] = useState([]);
  const [filteredUsage, setFilteredUsage] = useState([]);
  const [response, setResponse] = useState("");
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");
  const [query, setQuery] = useState("");

  useEffect(() => {
    setFilteredUsage(
      usage.filter((u) =>
        u.url.toLowerCase().includes(query.toLowerCase())
      )
    );
  }, [query, usage]);

  const signup = async () => {
    setLoading(true);
    const res = await axios.post(`${API}/auth/signup`, { email });
    setApiKey(res.data.apiKey);
    setLoading(false);
    setMessage("✨ API Key Generated");
  };

  const callAPI = async () => {
    setLoading(true);
    const res = await axios.get(
      `${API}/proxy?url=https://jsonplaceholder.typicode.com/todos/1&apiKey=${apiKey}`
    );
    setResponse(JSON.stringify(res.data, null, 2));
    setLoading(false);
  };

  const fetchUsage = async () => {
    const res = await axios.get(`${API}/usage/${apiKey}`);
    setUsage(res.data);
  };

  const billing = (usage.length * 0.2).toFixed(2);

  return (
    <div style={styles.container}>

      {/* NAVBAR */}
      <div style={styles.navbar}>
        <h2>💖 MeterFlow</h2>
        <div style={styles.navItems}>
          <span>Dashboard</span>
          <span>API Keys</span>
          <span>Usage</span>
          <span>Billing</span>
        </div>
      </div>

      <div style={styles.main}>
        <h1>✨ Developer Dashboard</h1>
        <p style={styles.message}>{message}</p>

        {/* CARDS */}
        <div style={styles.cards}>
          <Card title="Requests" value={usage.length} />
          <Card title="Billing" value={`₹${billing}`} />
          <Card title="Status" value={apiKey ? "Active 💅" : "Inactive"} />
        </div>

        {/* API KEY */}
        <div style={styles.card}>
          <input
            placeholder="Enter email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            style={styles.input}
          />
          <button style={styles.btn} onClick={signup}>
            {loading ? "..." : "Generate Key"}
          </button>
          {apiKey && <p style={styles.key}>{apiKey}</p>}
        </div>

        {/* PLAYGROUND */}
        {apiKey && (
          <div style={styles.card}>
            <button style={styles.btn} onClick={callAPI}>
              Call API
            </button>
            <button style={styles.btnOutline} onClick={fetchUsage}>
              Load Usage
            </button>
            {response && <pre style={styles.pre}>{response}</pre>}
          </div>
        )}

        {/* SEARCH */}
        <input
          style={styles.input}
          placeholder="🔍 Search logs..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        />

        {/* TABLE */}
        <div style={styles.card}>
          <table style={styles.table}>
            <thead>
              <tr>
                <th>URL</th>
                <th>Status</th>
                <th>Time</th>
              </tr>
            </thead>
            <tbody>
              {filteredUsage.map((u, i) => (
                <tr key={i}>
                  <td>{u.url}</td>
                  <td>{u.status}</td>
                  <td>{new Date(u.timestamp).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

      </div>
    </div>
  );
}

function Card({ title, value }) {
  return (
    <div style={styles.card}>
      <h4>{title}</h4>
      <h2>{value}</h2>
    </div>
  );
}

const styles = {
  container: {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #fdf2f8, #ede9fe)",
    fontFamily: "Segoe UI",
  },

  navbar: {
    display: "flex",
    justifyContent: "space-between",
    padding: "20px",
    background: "rgba(255,255,255,0.6)",
    backdropFilter: "blur(10px)",
    borderBottom: "1px solid #ddd",
  },

  navItems: {
    display: "flex",
    gap: "20px",
    fontWeight: "500",
  },

  main: {
    padding: "30px",
  },

  message: {
    color: "#ec4899",
    marginBottom: "10px",
  },

  cards: {
    display: "flex",
    gap: "15px",
    marginBottom: "20px",
  },

  card: {
    flex: 1,
    background: "rgba(255,255,255,0.6)",
    backdropFilter: "blur(10px)",
    padding: "20px",
    borderRadius: "16px",
    boxShadow: "0 8px 30px rgba(0,0,0,0.1)",
  },

  input: {
    padding: "10px",
    marginRight: "10px",
    borderRadius: "10px",
    border: "1px solid #ddd",
  },

  btn: {
    background: "linear-gradient(135deg, #ec4899, #8b5cf6)",
    color: "white",
    border: "none",
    padding: "10px 15px",
    borderRadius: "10px",
    cursor: "pointer",
    marginRight: "10px",
    boxShadow: "0 5px 15px rgba(236,72,153,0.3)",
  },

  btnOutline: {
    background: "white",
    border: "1px solid #ec4899",
    color: "#ec4899",
    padding: "10px 15px",
    borderRadius: "10px",
    cursor: "pointer",
  },

  key: {
    marginTop: "10px",
    fontSize: "12px",
    color: "#6b7280",
  },

  pre: {
    background: "#020617",
    color: "#22c55e",
    padding: "10px",
    marginTop: "10px",
    borderRadius: "10px",
  },

  table: {
    width: "100%",
    marginTop: "10px",
  },
};
